      <p id="sait_name">DSPARK STORE</p>
      <div id="profile">
        <p id="profile_name">User name</p>
        <img src={Image} alt="Ну нету авы, я что сделаю!" id="profile_image"></img>
      </div>
    </header>
    )
}

export default Header;
